import anthropic, json

client = anthropic.Anthropic()

# Simulated tools — in production, call real search/scraping APIs
def search_web(query: str) -> list:
    return [{"title": f"Result for {query}", "url": f"https://example.com/{i}", "snippet": "..."}
            for i in range(3)]

def fetch_page(url: str) -> str:
    return f"[Full text of {url}: pricing page content, feature list, ...]"

def save_report(filename: str, content: str) -> str:
    with open(filename, "w") as f: f.write(content)
    return f"Saved {len(content)} chars to {filename}"

TOOLS = [
    {"name": "search_web",  "description": "Search the web",
     "input_schema": {"type": "object", "properties": {"query": {"type": "string"}}, "required": ["query"]}},
    {"name": "fetch_page",  "description": "Fetch a web page",
     "input_schema": {"type": "object", "properties": {"url": {"type": "string"}},   "required": ["url"]}},
    {"name": "save_report", "description": "Save a report to disk",
     "input_schema": {"type": "object", "properties": {"filename": {"type": "string"}, "content": {"type": "string"}}, "required": ["filename", "content"]}},
]
TOOL_REGISTRY = {"search_web": search_web, "fetch_page": fetch_page, "save_report": save_report}

def research_agent(goal: str) -> str:
    messages = [{"role": "user", "content": goal}]
    for _ in range(20):
        r = client.messages.create(model="claude-opus-4-8", max_tokens=2048, tools=TOOLS, messages=messages)
        if r.stop_reason == "end_turn":
            return next(b.text for b in r.content if hasattr(b, "text"))
        results = []
        for b in r.content:
            if b.type == "tool_use":
                out = TOOL_REGISTRY[b.name](**b.input)
                results.append({"type": "tool_result", "tool_use_id": b.id, "content": json.dumps(out)})
        messages += [{"role": "assistant", "content": r.content}, {"role": "user", "content": results}]
    return "Limit reached."

# The agent searches, reads pages, synthesizes findings, and saves the report — autonomously
research_agent(
    "Research the top 3 vector database products (pricing, features, limits). "
    "Save a comparison report to vector_db_report.md"
)

# BAD: agentic loop for a task that needs exactly one LLM call
def translate_text_agent(text: str, language: str) -> str:
    # Running an agent loop for translation is unnecessary overhead.
    # The agent will call a translation tool... which calls the LLM once anyway.
    return run_agent(f"Translate this to {language}: {text}")

# GOOD: direct generative AI call
def translate_text(text: str, language: str) -> str:
    r = client.messages.create(
        model="claude-haiku-4-5-20251001", max_tokens=2048,
        system=f"Translate the user's text to {language}. Output only the translation.",
        messages=[{"role": "user", "content": text}]
    )
    return r.content[0].text
